export function initImageLazyLoading(){const images=document.querySelectorAll('img.lazy-image,img[data-src]');if('IntersectionObserver' in window){const imageObserver=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){const img=entry.target;loadImage(img);observer.unobserve(img);}});},{rootMargin: '50px 0px',threshold: 0.01});images.forEach(img=>imageObserver.observe(img));}else{images.forEach(img=>loadImage(img));}}function loadImage(img){const src=img.dataset.src;const srcset=img.dataset.srcset;if(!src)return;img.classList.add('loading');if(img.dataset.placeholder){img.src=img.dataset.placeholder;}const fullImage=new Image();fullImage.src=src;fullImage.onload=()=>{img.src=src;if(srcset)img.srcset=srcset;img.classList.remove('loading');img.classList.add('loaded');};fullImage.onerror=()=>{img.classList.add('error');};}const loadedModules=new Map();export async function lazyLoadModule(moduleName,modulePath){if(loadedModules.has(moduleName)){return loadedModules.get(moduleName);}try{const module=await import(modulePath);loadedModules.set(moduleName,module);return module;}catch(error){throw error;}}export async function lazyLoadModules(modules){const results=await Promise.all(modules.map(({name,path})=>lazyLoadModule(name,path).then(module=>({name,module}))));return new Map(results.map(({name,module})=>[name,module]));}const loadedScripts=new Set();export function lazyLoadScript(src,name){return new Promise((resolve,reject)=>{if(loadedScripts.has(name)){resolve(document.querySelector(`script[src="${src}"]`));return;}const existing=document.querySelector(`script[src="${src}"]`);if(existing){loadedScripts.add(name);resolve(existing);return;}const script=document.createElement('script');script.src=src;script.async=true;script.onload=()=>{loadedScripts.add(name);resolve(script);};script.onerror=()=>{reject(new Error(`Failed to load script: ${src}`));};document.head.appendChild(script);});}export function lazyLoadStylesheet(href,name){return new Promise((resolve,reject)=>{const existing=document.querySelector(`link[href="${href}"]`);if(existing){resolve(existing);return;}const link=document.createElement('link');link.rel='stylesheet';link.href=href;link.onload=()=>resolve(link);link.onerror=()=>reject(new Error(`Failed to load stylesheet: ${href}`));document.head.appendChild(link);});}export function lazyLoadComponent(selector,loadFn){const element=document.querySelector(selector);if(!element)return;if('IntersectionObserver' in window){const observer=new IntersectionObserver((entries,obs)=>{entries.forEach(entry=>{if(entry.isIntersecting){loadFn(element);obs.unobserve(element);}});},{rootMargin: '100px 0px',threshold: 0.01});observer.observe(element);}else{loadFn(element);}}export function initVirtualScroll(container,items,renderItem,itemHeight=60){const viewportHeight=container.clientHeight;const visibleCount=Math.ceil(viewportHeight/itemHeight)+2;let startIndex=0;let endIndex=visibleCount;function render(){const scrollTop=container.scrollTop;const newStartIndex=Math.floor(scrollTop/itemHeight);const newEndIndex=Math.min(newStartIndex+visibleCount,items.length);if(newStartIndex===startIndex&&newEndIndex===endIndex)return;startIndex=newStartIndex;endIndex=newEndIndex;container.innerHTML='';container.style.height=`${items.length*itemHeight}px`;container.style.position='relative';const fragment=document.createDocumentFragment();for(let i=startIndex;i<endIndex;i++){const item=renderItem(items[i],i);item.style.position='absolute';item.style.top=`${i*itemHeight}px`;item.style.left='0';item.style.right='0';fragment.appendChild(item);}container.appendChild(fragment);}container.addEventListener('scroll',render,{passive: true});render();return{destroy:()=>container.removeEventListener('scroll',render)};}export function initLazyLoading(){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{initImageLazyLoading();});}else{initImageLazyLoading();}}if(typeof document!=='undefined'){initLazyLoading();}